#!/usr/bin/env node

const axios = require('axios');

/**
 * Sends test report email to PR author
 */

async function sendEmailNotification(config) {
  const {
    prAuthor,
    prAuthorEmail,
    prNumber,
    prTitle,
    reportUrl,
    healthScore,
    impactScore,
    totalTests,
    passedTests,
    failedTests,
    failuresFound,
  } = config;

  // For now, we'll log the email that would be sent
  // In production, you'd use SendGrid, AWS SES, or GitHub Actions built-in email
  
  const emailContent = `
Subject: PR #${prNumber} Test Report - ${failuresFound ? '❌ FAILURES' : '✅ PASSED'}

Dear ${prAuthor},

Your PR #${prNumber} "${prTitle}" has completed testing.

📊 Test Summary:
- Total Tests: ${totalTests}
- ✅ Passed: ${passedTests}
- ❌ Failed: ${failedTests}
- Pass Rate: ${totalTests > 0 ? Math.round((passedTests / totalTests) * 100) : 0}%

📈 PR Health Score: ${healthScore}%
⚠️ Impact Score: ${impactScore}/100

📋 Detailed Report:
${reportUrl}

${failuresFound ? `
⚠️ Issues Detected:
Please review the detailed report for more information about the failures.
Check JIRA for automatically created issues.
` : `
✅ All tests passed! Your PR is ready to merge.
`}

---
Generated by 🤖 AI-Powered Smart Testing Pipeline
${new Date().toLocaleString()}
  `;

  console.log('📧 Email Summary:');
  console.log(`To: ${prAuthorEmail}`);
  console.log(`Subject: PR #${prNumber} Test Report - ${failuresFound ? '❌ FAILURES' : '✅ PASSED'}`);
  console.log(`Report URL: ${reportUrl}`);
  
  // Set GitHub Actions output
  console.log('✅ Email notification prepared (in real deployment, use SendGrid/SES)');

  return {
    to: prAuthorEmail,
    subject: `PR #${prNumber} Test Report - ${failuresFound ? '❌ FAILURES' : '✅ PASSED'}`,
    body: emailContent,
    reportUrl,
  };
}

// Main execution
async function main() {
  try {
    const config = {
      prAuthor: process.env.PR_AUTHOR || 'Developer',
      prAuthorEmail: process.env.PR_AUTHOR_EMAIL || 'author@example.com',
      prNumber: process.env.PR_NUMBER || '1',
      prTitle: process.env.PR_TITLE || 'Test PR',
      reportUrl: process.env.REPORT_URL || 'https://example.com/report',
      healthScore: parseInt(process.env.HEALTH_SCORE || '0'),
      impactScore: parseInt(process.env.IMPACT_SCORE || '0'),
      totalTests: parseInt(process.env.TOTAL_TESTS || '0'),
      passedTests: parseInt(process.env.PASSED_TESTS || '0'),
      failedTests: parseInt(process.env.FAILED_TESTS || '0'),
      failuresFound: process.env.FAILURES_FOUND === 'true',
    };

    await sendEmailNotification(config);
    console.log('\n✅ Email notification sent successfully');

  } catch (error) {
    console.error('❌ Error sending email:', error);
    process.exit(1);
  }
}

main();
